/* BTPagination — Figma node 749-2846 */

/* ── Root ──────────────────────────────────────────────────────────────────── */

.bt-pagination {
  display: flex;
  align-items: center;
  width: 100%;
  font-family: inherit;
}

.bt-pagination--number {
  gap: var(--space-lg);
}

.bt-pagination--display,
.bt-pagination--step {
  justify-content: space-between;
}

/* ── Nav button group ───────────────────────────────────────────────────────── */

.bt-pagination__nav {
  display: inline-flex;
  align-items: center;
  gap: var(--space-sm);
}

/* ── Pages center section ───────────────────────────────────────────────────── */

.bt-pagination__pages {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
  flex: 1;
  justify-content: center;
}

/* ── Individual page pill ───────────────────────────────────────────────────── */

.bt-pagination__page {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 32px;
  height: 32px;
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  cursor: pointer;
  background: transparent;
  transition: background 100ms ease, border-color 100ms ease;
  flex-shrink: 0;
}

.bt-pagination__page:hover:not(.bt-pagination__page--active):not(.bt-pagination__page--ellipsis) {
  background: var(--bg-subtle);
}

.bt-pagination__page--active {
  background: var(--bg-subtle);
  border-color: var(--color-brand-primary);
}

.bt-pagination__page--ellipsis {
  border: none;
  pointer-events: none;
  cursor: default;
  color: var(--text-secondary);
}

/* ── Display variant ────────────────────────────────────────────────────────── */

.bt-pagination__display-left {
  display: flex;
  align-items: center;
  gap: var(--space-sm);
}

.bt-pagination__rows-label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-secondary);
  white-space: nowrap;
}

/* Rows-per-page trigger button (wraps the BTDropdown custom trigger) */
.bt-pagination__rows-trigger {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-sm);
  padding: 6px var(--space-sm);
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  color: var(--text-primary);
  background: transparent;
  cursor: pointer;
  font-family: inherit;
  transition: border-color 100ms ease, background 100ms ease;
  white-space: nowrap;
}

.bt-pagination__rows-trigger:hover {
  background: var(--bg-subtle);
}

.bt-pagination__rows-trigger--open,
.bt-pagination__rows-trigger:focus-visible {
  outline: none;
  border-color: var(--color-brand-primary);
}

/* Chevron rotates when open.
   transform-box: fill-box + transform-origin: center ensures the SVG rotates
   around its own visual centre, not the SVG coordinate-system origin (0 0). */
.bt-pagination__rows-chevron-icon {
  display: block;
  flex-shrink: 0;
  transform-box: fill-box;
  transform-origin: center;
  transition: transform 150ms ease;
}

.bt-pagination__rows-chevron-icon--open {
  transform: rotate(180deg);
}

/* ── RTL ─────────────────────────────────────────────────────────────────────
 * Auto-mirrors via host `dir="rtl"` — flex auto-reverses button order, labels
 * stay tied to their semantic button (Previous = page-1, Next = page+1), so
 * "Previous" sits on the visual right and "Next" on the visual left in RTL.
 * The only thing CSS can't auto-flip is the chevron SVG glyph itself — mirror
 * it via a scoped transform so chevrons always point the right way. */
[dir="rtl"] .bt-pagination__icon svg {
  transform: scaleX(-1);
}

/* ── Step variant ───────────────────────────────────────────────────────────── */

.bt-pagination__step-label {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  color: var(--text-primary);
}

/* Step nav: 16px gap between Prev and Next buttons */
.bt-pagination__nav--step {
  gap: var(--space-lg);
}

/* ── Icon wrapper ───────────────────────────────────────────────────────────── */

.bt-pagination__icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 16px;
  height: 16px;
  flex-shrink: 0;
}

.bt-pagination__icon > svg {
  width: 16px;
  height: 16px;
  display: block;
}

/**
 * BTPagination — data pagination molecule (React).
 * Figma: node 749-2846.
 *
 * @example number
 * ```tsx
 * <BTPagination currentPage={page} totalPages={20} onPageChange={setPage} />
 * ```
 *
 * @example display
 * ```tsx
 * <BTPagination
 *   variant="display"
 *   currentPage={page}
 *   totalCount={137}
 *   rowsPerPage={rowsPerPage}
 *   rowsPerPageOptions={[10, 20, 50]}
 *   onPageChange={setPage}
 *   onRowsChange={setRowsPerPage}
 * />
 * ```
 *
 * @example step
 * ```tsx
 * <BTPagination
 *   variant="step"
 *   currentStep={step}
 *   totalSteps={5}
 *   onPrev={() => setStep(s => Math.max(1, s - 1))}
 *   onNext={() => setStep(s => Math.min(5, s + 1))}
 * />
 * ```
 */
import './BTPagination.css';
import type { BTPaginationProps } from './BTPagination.types';
import { BTStepNumber } from '../step-number/BTStepNumber';
import { BTDropdown } from '../dropdown/BTDropdown';
import { BTButton } from '../button/BTButton';
import type { BTDropdownItem } from '../dropdown-list/BTDropdownList.types';

// ── Inline SVG icons ─────────────────────────────────────────────────────────

function IconChevronLeft() {
  return (
    <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      <path d="M15.41 7.41L14 6L8 12L14 18L15.41 16.59L10.83 12L15.41 7.41Z" fill="currentColor"/>
    </svg>
  );
}

function IconChevronRight() {
  return (
    <svg viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      <path d="M8.59 16.59L10 18L16 12L10 6L8.59 7.41L13.17 12L8.59 16.59Z" fill="currentColor"/>
    </svg>
  );
}

function IconChevronDown({ open }: { open?: boolean }) {
  return (
    <svg
      viewBox="0 0 24 24"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      aria-hidden="true"
      className={[
        'bt-pagination__rows-chevron-icon',
        open && 'bt-pagination__rows-chevron-icon--open',
      ].filter(Boolean).join(' ')}
    >
      <path d="M7.41 8.59L12 13.17L16.59 8.59L18 10L12 16L6 10L7.41 8.59Z" fill="currentColor"/>
    </svg>
  );
}

function IconFirstPage() {
  return (
    // viewBox pads the 8.27×8 path to match Figma's 25% inset inside a 16px icon container
    <svg viewBox="-4 -4 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      <path d="M0 8V0H1.33333V8H0ZM7.33333 8L3.33333 4L7.33333 0L8.26667 0.933333L5.2 4L8.26667 7.06667L7.33333 8Z" fill="currentColor"/>
    </svg>
  );
}

function IconLastPage() {
  return (
    // viewBox pads the 8.27×8 path to match Figma's 25% inset inside a 16px icon container
    <svg viewBox="-4 -4 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      <path d="M0.933333 8L0 7.06667L3.06667 4L0 0.933333L0.933333 0L4.93333 4L0.933333 8ZM6.93333 8V0H8.26667V8H6.93333Z" fill="currentColor"/>
    </svg>
  );
}

// ── Windowing algorithm ──────────────────────────────────────────────────────

type PageItem = number | 'ellipsis';

function buildVisiblePages(currentPage: number, totalPages: number): PageItem[] {
  if (totalPages <= 7) {
    return Array.from({ length: totalPages }, (_, i) => i + 1);
  }
  if (currentPage <= 4) {
    return [1, 2, 3, 4, 5, 'ellipsis', totalPages];
  }
  if (currentPage >= totalPages - 3) {
    return [
      1,
      'ellipsis',
      totalPages - 4,
      totalPages - 3,
      totalPages - 2,
      totalPages - 1,
      totalPages,
    ];
  }
  return [
    1,
    'ellipsis',
    currentPage - 1,
    currentPage,
    currentPage + 1,
    'ellipsis',
    totalPages,
  ];
}

// ── Props extension for React callbacks ─────────────────────────────────────

export interface BTPaginationReactProps extends BTPaginationProps {
  onPageChange?: (page: number) => void;
  onRowsChange?: (rows: number) => void;
  onPrev?: () => void;
  onNext?: () => void;
}

// ── Component ────────────────────────────────────────────────────────────────

export function BTPagination({
  variant = 'number',
  currentPage = 1,
  totalPages = 1,
  rowsPerPage = 10,
  rowsPerPageOptions = [10, 20, 50],
  currentStep = 1,
  totalSteps = 1,
  ariaLabel = 'Pagination',
  onPageChange,
  onRowsChange,
  onPrev,
  onNext,
}: BTPaginationReactProps) {
  const isFirstPage = currentPage <= 1;
  const isLastPage  = currentPage >= totalPages;

  // RTL handling — no detection needed. Component auto-mirrors via CSS logical
  // properties + native flex direction. Labels stay tied to their semantic
  // button (Previous → page-1, Next → page+1); in RTL the flex auto-reverses
  // so "Previous" visually sits on the right and "Next" on the left. Chevron
  // SVGs are mirrored via scoped CSS in BTPagination.css.

  function goTo(page: number) {
    if (page < 1 || page > totalPages || page === currentPage) return;
    onPageChange?.(page);
  }

  const visiblePages = buildVisiblePages(currentPage, totalPages);

  const rowsItems: BTDropdownItem<number>[] = rowsPerPageOptions.map((opt) => ({
    value: opt,
    label: String(opt),
    checked: opt === rowsPerPage,
  }));

  return (
    <nav
      className={`bt-pagination bt-pagination--${variant}`}
      role="navigation"
      aria-label={ariaLabel}
    >
      {/* ── NUMBER variant ─────────────────────────────────────────────── */}
      {variant === 'number' && (
        <>
          {/* Left nav */}
          <div className="bt-pagination__nav">
            <BTButton variant="ghost" size="small" iconOnly disabled={isFirstPage} aria-label="First page" onClick={() => goTo(1)}>
              <span className="bt-pagination__icon"><IconFirstPage /></span>
            </BTButton>
            <BTButton
              variant="ghost"
              size="small"
              label="Previous"
              disabled={isFirstPage}
              aria-label="Previous page"
              onClick={() => goTo(currentPage - 1)}
              leftIcon={<span className="bt-pagination__icon"><IconChevronLeft /></span>}
            />
          </div>

          {/* Center pages — BTStepNumber pills */}
          <div className="bt-pagination__pages" role="list">
            {visiblePages.map((page, idx) => (
              <BTStepNumber
                key={page === 'ellipsis' ? `ellipsis-${idx}` : page}
                page={page === 'ellipsis' ? 0 : (page as number)}
                isActive={page !== 'ellipsis' && page === currentPage}
                isEllipsis={page === 'ellipsis'}
                onClick={page !== 'ellipsis' ? () => goTo(page as number) : undefined}
              />
            ))}
          </div>

          {/* Right nav */}
          <div className="bt-pagination__nav">
            <BTButton
              variant="ghost"
              size="small"
              label="Next"
              disabled={isLastPage}
              aria-label="Next page"
              onClick={() => goTo(currentPage + 1)}
              rightIcon={<span className="bt-pagination__icon"><IconChevronRight /></span>}
            />
            <BTButton variant="ghost" size="small" iconOnly disabled={isLastPage} aria-label="Last page" onClick={() => goTo(totalPages)}>
              <span className="bt-pagination__icon"><IconLastPage /></span>
            </BTButton>
          </div>
        </>
      )}

      {/* ── DISPLAY variant ──────────────────────────────────────────────── */}
      {variant === 'display' && (
        <>
          <div className="bt-pagination__display-left">
            <span className="bt-pagination__rows-label">Rows per page</span>
            <BTDropdown<number>
              items={rowsItems}
              value={rowsPerPage}
              onSelect={(v) => onRowsChange?.(v)}
              trigger={(toggle, isOpen) => (
                <button
                  className={`bt-pagination__rows-trigger${isOpen ? ' bt-pagination__rows-trigger--open' : ''}`}
                  aria-label={`Rows per page, currently ${rowsPerPage}`}
                  aria-expanded={isOpen}
                  onClick={toggle}
                >
                  {rowsPerPage}
                  <span className="bt-pagination__icon">
                    <IconChevronDown open={isOpen} />
                  </span>
                </button>
              )}
            />
          </div>

          <div className="bt-pagination__nav">
            <BTButton
              variant="ghost"
              size="small"
              label="Previous"
              disabled={isFirstPage}
              aria-label="Previous page"
              onClick={() => goTo(currentPage - 1)}
              leftIcon={<span className="bt-pagination__icon"><IconChevronLeft /></span>}
            />
            <BTButton
              variant="ghost"
              size="small"
              label="Next"
              disabled={isLastPage}
              aria-label="Next page"
              onClick={() => goTo(currentPage + 1)}
              rightIcon={<span className="bt-pagination__icon"><IconChevronRight /></span>}
            />
          </div>
        </>
      )}

      {/* ── STEP variant ─────────────────────────────────────────────────── */}
      {variant === 'step' && (
        <>
          <span className="bt-pagination__step-label">
            Step {currentStep} of {totalSteps}
          </span>

          {/* Prev / Next — secondary-light, 16px gap */}
          <div className="bt-pagination__nav bt-pagination__nav--step">
            <BTButton
              variant="secondary-light"
              label="Prev"
              disabled={currentStep <= 1}
              aria-label="Previous step"
              onClick={onPrev}
            />
            <BTButton
              variant="secondary-light"
              label="Next"
              disabled={currentStep >= totalSteps}
              aria-label="Next step"
              onClick={onNext}
            />
          </div>
        </>
      )}
    </nav>
  );
}

BTPagination.displayName = 'BTPagination';

/**
 * BTPagination — data pagination molecule.
 * Figma: node 749-2846.
 *
 * Three variants:
 * - 'number'  Full numbered paging with first/prev/pages/next/last.
 * - 'display' Rows-per-page selector + prev/next.
 * - 'step'    Step N of M + Prev/Next.
 */
export type BTPaginationVariant = 'display' | 'step' | 'number';

export interface BTPaginationProps {
  /** Which pagination pattern to render. @default 'number' */
  variant?: BTPaginationVariant;

  // ── number + display ─────────────────────────────────────────────────────
  /** Current active page (1-indexed). */
  currentPage?: number;
  /** Total number of pages. Required for 'number' variant. */
  totalPages?: number;

  // ── display ──────────────────────────────────────────────────────────────
  /** Total item count — used in range label display. */
  totalCount?: number;
  /** Items shown per page. @default 10 */
  rowsPerPage?: number;
  /** Rows-per-page dropdown options. @default [10, 20, 50] */
  rowsPerPageOptions?: number[];

  // ── step ─────────────────────────────────────────────────────────────────
  /** Current step (1-indexed). Required for 'step' variant. */
  currentStep?: number;
  /** Total steps. Required for 'step' variant. */
  totalSteps?: number;

  /** Accessible label for the nav wrapper. @default 'Pagination' */
  ariaLabel?: string;
}

export { BTPagination } from './BTPagination';
export type { BTPaginationReactProps } from './BTPagination';
export type { BTPaginationProps, BTPaginationVariant } from './BTPagination.types';
